function bmul(uint a, uint b)
        internal pure
        returns (uint)
    {
        uint c0 = a * b;
        require(a == 0 || c0 / a == b, "ERR_MUL_OVERFLOW");
        uint c1 = c0 + (BONE / 2);
        require(c1 >= c0, "ERR_MUL_OVERFLOW");
        uint c2 = c1 / BONE;
        return c2;
    }

function _addFacet(address facet_, bytes4[] memory selectors_) internal virtual {
    _checkIfFacetIsValid(facet_, selectors_);

    DStorage storage _ds = _getDiamondStorage();

    for (uint256 i = 0; i < selectors_.length; ++i) {
        if (_ds.selectorToFacet[selectors_[i]] != address(0))
            revert SelectorAlreadyAdded(_ds.selectorToFacet[selectors_[i]], selectors_[i]);

        _ds.selectorToFacet[selectors_[i]] = facet_;
        _ds.facetToSelectors[facet_].add(bytes32(selectors_[i]));
    }

    _ds.facets.add(facet_);
}

function _removeNft(address nftContract, uint256 tokenId) internal {
  uint256 len = nfts.length;
  for (uint256 i = 0; i < len; i++) {
    Nft memory nftInfo = nfts[i];
    if (nftContract == nftInfo.nftContract && tokenId == nftInfo.tokenId) {
      if(i != len - 1) {
        nfts[i] = nfts[len - 1];
      }
      nfts.pop();
      emit RemoveNftToken(nftContract, tokenId);
      break;
    }
  }
}

function bdiv(uint a, uint b)
        internal pure
        returns (uint)
    {
        require(b != 0, "ERR_DIV_ZERO");
        uint c0 = a * BONE;
        require(a == 0 || c0 / a == BONE, "ERR_DIV_INTERNAL"); // bmul overflow
        uint c1 = c0 + (b / 2);
        require(c1 >= c0, "ERR_DIV_INTERNAL"); //  badd require
        uint c2 = c1 / b;
        return c2;
    }

function bpowi(uint a, uint n)
        internal pure
        returns (uint)
    {
        uint z = n % 2 != 0 ? a : BONE;

        for (n /= 2; n != 0; n /= 2) {
            a = bmul(a, a);

            if (n % 2 != 0) {
                z = bmul(z, a);
            }
        }
        return z;
    }

function flux(bytes32 ilk, address src, address dst, uint256 wad) external {
    require(wish(src, msg.sender), "Vat/not-allowed");
    gem[ilk][src] = _sub(gem[ilk][src], wad);
    gem[ilk][dst] = _add(gem[ilk][dst], wad);
}
function move(address src, address dst, uint256 rad) external {
    require(wish(src, msg.sender), "Vat/not-allowed");
    dai[src] = _sub(dai[src], rad);
    dai[dst] = _add(dai[dst], rad);
}

function drip() external returns (uint tmp) {
    require(now >= rho, "Pot/invalid-now");
    tmp = _rmul(_rpow(dsr, now - rho, ONE), chi);
    uint chi_ = _sub(tmp, chi);
    chi = tmp;
    rho = now;
    vat.suck(address(vow), address(this), _mul(Pie, chi_));
}

function heal(uint rad) external {
    require(rad <= vat.dai(address(this)), "Vow/insufficient-surplus");
    require(rad <= sub(sub(vat.sin(address(this)), Sin), Ash), "Vow/insufficient-debt");
    vat.heal(rad);
}
function kiss(uint rad) external {
    require(rad <= Ash, "Vow/not-enough-ash");
    require(rad <= vat.dai(address(this)), "Vow/insufficient-surplus");
    Ash = sub(Ash, rad);
    vat.heal(rad);
}

function flow(bytes32 ilk) external {
    require(debt != 0, "End/debt-zero");
    require(fix[ilk] == 0, "End/fix-ilk-already-defined");

    (, uint256 rate,,,) = vat.ilks(ilk);
    uint256 wad = rmul(rmul(Art[ilk], rate), tag[ilk]);
    fix[ilk] = mul(sub(wad, gap[ilk]), RAY) / (debt / RAY);
    emit Flow(ilk);
}

function load(address src) external {
    require(live == 0, "Cure/still-live");
    require(pos[src] > 0, "Cure/non-existing-source");
    uint256 oldAmt_ = amt[src];
    uint256 newAmt_ = amt[src] = SourceLike(src).cure();
    say = _add(_sub(say, oldAmt_), newAmt_);
    if (loaded[src] == 0) {
        loaded[src] = 1;
        lCount++;
    }
    emit Load(src);
}

function compatDecimals(IERC20Token token) internal view returns (uint8 tokenDecimals) {
    tokenDecimals = 18;
    (bool didSucceed, bytes memory resultData) = address(token).staticcall(DECIMALS_CALL_DATA);
    if (didSucceed && resultData.length >= 32) {
        tokenDecimals = uint8(LibBytesV06.readUint256(resultData, 0));
    }
}

function transferFrom(address _from, address _to, uint256 _value) public returns (bool) {
    uint256 allowance = allowed[_from][msg.sender];
    if (balances[_from] >= _value && allowance >= _value && balances[_to] + _value >= balances[_to]) {
        balances[_to] += _value;
        balances[_from] -= _value;
        if (allowance < MAX_UINT) {
            allowed[_from][msg.sender] -= _value;
        }
        Transfer(_from, _to, _value);
        return true;
    } else {
        return false;
    }
}

function _removeOwners(address[] memory oldOwners_) private {
    AMultiOwnableStorage storage $ = _getAMultiOwnableStorage();

    for (uint256 i = 0; i < oldOwners_.length; ++i) {
        $.owners.remove(oldOwners_[i]);
    }

    emit OwnersRemoved(oldOwners_);
}

function _addSigners(address[] memory signers_) internal virtual {
    if (signers_.length == 0) revert InvalidSigners();

    ABridgeStorage storage $ = _getABridgeStorage();

    for (uint256 i = 0; i < signers_.length; ++i) {
        if (signers_[i] == address(0)) revert InvalidSigner(signers_[i]);

        $.signers.add(signers_[i]);
    }
}

function depositERC721(address nftContract, uint256[] memory tokenIds) public {
    require(nftContract != address(0), "DODONftVault: ZERO_ADDRESS");
    for(uint256 i = 0; i < tokenIds.length; i++) {
        IERC721(nftContract).safeTransferFrom(msg.sender, address(this), tokenIds[i]);
        // emit AddNftToken(nftContract, tokenIds[i], 1);
    }
}

function safeTransferFrom(address _from, address _to, uint256 _id, uint256 _value, bytes calldata _data) external /*payable*/  {
    if (msg.sender != _from) {
        allowances[_from][msg.sender][_id] = allowances[_from][msg.sender][_id].sub(_value);
    }
    targetContract.safeTransferFrom(_from, _to, _id, _value, _data);
}

function safeBatchTransferFrom(address _from, address _to, uint256[] calldata _ids, uint256[] calldata _values, bytes calldata _data) external /*payable*/ {
    if (msg.sender != _from) {
        for (uint256 i = 0; i < _ids.length; ++i) {
            allowances[_from][msg.sender][_ids[i]] = allowances[_from][msg.sender][_ids[i]].sub(_values[i]);
        }
    }
    targetContract.safeBatchTransferFrom(_from, _to, _ids, _values, _data);
}

function getNodeModelsFucus(
    uint256 nodeId
) external view returns (uint256[] memory allocatedFucus) {
    uint256 length = nodeSupportedModels[nodeId].length();
    allocatedFucus = new uint256[](length);

    for (uint256 i = 0; i < length; i++) {
        uint256 modelId = nodeSupportedModels[nodeId].at(i);
        allocatedFucus[i] = nodeModelConfigs[nodeId][modelId].allocatedFucus;
    }
}

function copyQuickBuyPath(IBancorConverter _oldConverter, IBancorConverter _newConverter) private {
    uint256 quickBuyPathLength = _oldConverter.getQuickBuyPathLength();
    if (quickBuyPathLength <= 0)
        return;

    IERC20Token[] memory path = new IERC20Token[](quickBuyPathLength);
    for (uint256 i = 0; i < quickBuyPathLength; i++) {
        path[i] = _oldConverter.quickBuyPath(i);
    }

    _newConverter.setQuickBuyPath(path);
}

function tokenURI(uint256 _tokenId) public view override returns (string memory) {
    require(_exists(_tokenId), "ERC721Metadata: URI query for nonexistent token");
    require(metadata != address(0), "ERC721Metadata: no metadata address");

    return IERC721TokenURI(metadata).tokenURI(_tokenId);
}

function cancelAsk(address _tokenContract, uint256 _tokenId) external nonReentrant {
    require(askForNFT[_tokenContract][_tokenId].seller != address(0), "cancelAsk ask doesn't exist");

    address tokenOwner = IERC721(_tokenContract).ownerOf(_tokenId);
    require(
        msg.sender == tokenOwner || IERC721(_tokenContract).isApprovedForAll(tokenOwner, msg.sender),
        "cancelAsk must be token owner or operator"
    );

    _cancelAsk(_tokenContract, _tokenId);
}

function balanceOfBatch(
    address[] memory accounts,
    uint256[] memory ids
) public view virtual override returns (uint256[] memory) {
    require(accounts.length == ids.length, "LENGTH_MISMATCH");

    uint256[] memory batchBalances = new uint256[](accounts.length);

    for (uint256 i = 0; i < accounts.length; ++i) {
        batchBalances[i] = balanceOf[accounts[i]][ids[i]];
    }

    return batchBalances;
}

